Here's a complete example of a Discord bot using Discord.js v14 that implements the `/ban` command as a slash command:

```javascript
const { Client, GatewayIntentBits, SlashCommandBuilder } = require('discord.js');

// Create a new client with the necessary intents
const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMembers,
    GatewayIntentBits.Messages
  ]
});

// Define the ban command
const banCommand = new SlashCommandBuilder()
  .setName('ban')
  .setDescription('Ban a user from the server')
  .addUserOption(option => 
    option.setName('user')
      .setDescription('The user to ban')
      .setRequired(true)
  )
  .addStringOption(option => 
    option.setName('reason')
      .setDescription('The reason for the ban')
      .setRequired(false)
  );

// Event listener for when the bot is ready
client.once('ready', () => {
  console.log(`Logged in as ${client.user.tag}`);

  // Register the ban command with the Discord API
  client.application.commands.create(banCommand);
});

// Event listener for incoming interactions
client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  // Handle the ban command
  if (interaction.commandName === 'ban') {
    const user = interaction.options.getUser('user');
    const reason = interaction.options.getString('reason') || 'No reason provided';

    // Check if the user is authorized to ban
    if (!interaction.memberPermissions.has('MODERATE_MEMBERS')) {
      return interaction.reply({ content: 'You don\'t have permission to ban users.', ephemeral: true });
    }

    // Check if the user is the same as the interaction member
    if (user.id === interaction.member.id) {
      return interaction.reply({ content: 'You can\'t ban yourself.', ephemeral: true });
    }

    // Attempt to ban the user
    try {
      await interaction.guild.members.ban(user, { reason });
      interaction.reply({ content: `${user.tag} has been banned. Reason: ${reason}`, ephemeral: true });
    } catch (error) {
      console.error('Error banning user:', error);
      interaction.reply({ content: 'An error occurred while trying to ban the user.', ephemeral: true });
    }
  }
});

// Log in the bot with your token
client.login('YOUR_BOT_TOKEN_HERE');
```

Before running this code, make sure to:

1. Replace `'YOUR_BOT_TOKEN_HERE'` with your actual bot token
2. Ensure your bot has the following permissions:
   - `Ban Members`
   - `Manage Members`
   - `View Channel` (for the channel where the command will be used)
3. Make sure the bot is in a server and has the necessary roles to perform bans

